-- @gate: add
-- Depends on 1102
-- ============================================================================
-- 1103_campaign_offer_scope.sql — core.campaign_offer_scope: FULL-UNIVERSE (3,290
-- campaign_ids) offer classification + funding-scope flag + owner attribution.
-- The durable exclusion table the charter (§3) requires — funding scope is a TABLE,
-- never an ad-hoc filter.
--
-- SOURCE: deliverables/2026-07-14-cold-email-bi/campaign-funding-scope.csv,
-- snapshot warehouse_20260714_141517_221.duckdb. Sam-validated 2026-07-14:
--   * HELOC (3) and tax_debt_relief (2) OUT of funding scope — CONFIRMED.
--   * section-125-2 campaigns named "funding 1/2" IN scope by name rule — CONFIRMED.
--   * MCA / MCA 2 = business funding -> IN scope.
-- Charter rule: IN = business_funding + equipment_financing; OUT = pre_ipo, section_125,
-- tariffs, rnd_credit, erc, heloc, tax_debt_relief, review_mgmt, other.
-- Expected distribution: 3106 in-scope / 174 out / 10 UNRESOLVED (in_funding_scope NULL).
--
-- OWNER CAVEAT (PENDING Sam ruling — encoded swappable): owner_cm applies the charter
-- default no-parenthetical -> IDO; owner_basis='default' marks exactly those 927 rows
-- (59.3M sends, heavily deleted-workspace campaigns with lost names). If Sam rules a
-- different default (e.g. workspace-implicit owner), ONLY owner_basis='default' rows
-- change — never touch owner_basis='name' rows.
--
-- MAINTENANCE: new campaigns are auto-appended nightly by entities/mof_bi_history.py
-- (OFFER-TAG-SPEC convention: untagged = business_funding, confidence low, evidence
-- marked auto-append) so the table self-maintains; re-classify by copy when needed.
--
-- Idempotent: ON CONFLICT (campaign_id) DO NOTHING (frozen human/Sam-validated rows are
-- never overwritten by re-apply or the auto-append). Reversible: DROP TABLE.
-- ============================================================================

CREATE SCHEMA IF NOT EXISTS core;

CREATE TABLE IF NOT EXISTS core.campaign_offer_scope (
  campaign_id        VARCHAR PRIMARY KEY,
  campaign_name      VARCHAR,
  workspace_slug     VARCHAR,
  offer_class        VARCHAR NOT NULL,  -- business_funding|equipment_financing|pre_ipo|section_125|tariffs|rnd_credit|erc|heloc|tax_debt_relief|review_mgmt|other|UNRESOLVED
  in_funding_scope   BOOLEAN,           -- NULL when UNRESOLVED
  classified_by      VARCHAR,           -- name|workspace|tag_hint|copy|default_untagged_new
  confidence         VARCHAR,           -- high|med|low
  evidence           VARCHAR,
  owner_cm           VARCHAR,
  owner_basis        VARCHAR,           -- name|workspace|default (default = PENDING Sam ruling)
  sent_lifetime      BIGINT,            -- as-of classification snapshot (context, not a live metric)
  first_send         DATE,
  last_send          DATE,
  source_table       VARCHAR,
  prior_core_offer   VARCHAR,
  prior_core_offer_source VARCHAR,
  classified_at      TIMESTAMPTZ DEFAULT now(),
  _source            VARCHAR DEFAULT 'deliverable-2026-07-14-cold-email-bi'
);

